var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"스승님, 정말 하실 건가요?","JPN":"師匠、本当にやるつもりですか？","ENG":"Are you sure you want to do this, Master?","TWN":"師父，真的要這樣做嗎？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"설마 지금까지 스승님이 해 오신 일들을 잊으신 건 아니겠죠?","JPN":"まさかこれまで師匠がやってきたことを忘れたわけではないですよね？","ENG":"You didn't forget what you've been doing all along, did you?","TWN":"師父不會忘了您一路以來做的事情吧？"},"stage":{"bg":"MAINSTREAM_5505011","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"<color=#ffd34c>그들</color>이 깨어나는 걸 막기 위해 클리포트 인자 보유자들을 그렇게 사냥해 왔었는데......","JPN":"<color=#ffd34c>彼ら</color>が目覚めるのを阻止するために、クリフォト・ファクター保持者たちを狩ってきましたが……","ENG":"You've spent so much effort hunting down Qliphoth Factor carriers to keep <color=#ffd34c>them</color> from awakening...","TWN":"您為了阻止<color=#ffd34c>他們</color>覺醒，一直在狩獵逆卡巴拉因子擁有者……"},"stage":{"bg":"MAINSTREAM_5505011","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"정작 스승님께서 그 힘을 개방하는 건 자기모순일 뿐입니다.","JPN":"いざ師匠がその力を開放するのは、自己矛盾でしかありません。","ENG":"You're denying all your past efforts by releasing the power yourself.","TWN":"但要是師父發動這個力量，那就只是自我矛盾而已。"},"stage":{"bg":"MAINSTREAM_5505011","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"......알고 있다.","JPN":"……わかってる。","ENG":"I know that.","TWN":"……我知道。"},"stage":{"bg":"MAINSTREAM_5505011","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"하지만 이미 <color=#ffd34c>설계도</color>가 되는 원본이 나유빈의 손에 들어간 이상, 이대로 방치하는 건 사태를 악화시킬 뿐이야.","JPN":"だが、<color=#ffd34c>設計図</color>になる原本をイチノセが手に入れた以上、\\nこのまま放置するのは状況を悪化させるだけだ。","ENG":"But the original copy, the one to serve as a <color=#ffd34c>blueprint</color>, has fallen into the hands of Na Yubin. Things will only get worse if I do nothing here.","TWN":"但<color=#ffd34c>設計圖</color>正本已經落入了羅瑜斌的手裡，放任不管只會讓事態惡化而已。"},"stage":{"bg":"MAINSTREAM_5505011","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L16_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"너도 눈치챘겠지?","JPN":"お前も気づいてるだろ？","ENG":"Didn't you notice?","TWN":"妳應該也發現了吧？"},"stage":{"bg":"MAINSTREAM_423010","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L17_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"테라사이드 시스템의 최종목적은 결국 클리포트 인자의 복제체를 만드는 거다.","JPN":"テラサイドシステムの最終目標は、\\nクリフォト・ファクターの複製体を作ることだ。","ENG":"The ultimate goal of System Terraside is to replicate the Qliphoth Factors.","TWN":"特拉賽德系統的最終目標是創造出逆卡巴拉因子的複製體。"},"stage":{"bg":"MAINSTREAM_423010","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L18_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"이대로 두면 대량으로 생산해 낸 클리포트 레플리카 인자로 놈이 무슨 짓을 할지 몰라.","JPN":"このまま放っておけば、大量に生産した\\nレプリカ・クリフォト・ファクターで奴が何をしでかすかわからない。","ENG":"If we let them be, they will raise all hell with the mass-produced Qliphoth Replica Factors.","TWN":"再這樣下去，不知道那些傢伙們會拿大量生產出來的逆卡巴拉複製因子做些什麼事情。"},"stage":{"bg":"MAINSTREAM_423010","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L19_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"이미 연쇄반응이 시작된 이상, 사태를 정리하려면 어느 정도 손해를 감수하더라도 압도적인 힘으로 끊어내 버리는 게 상책이다.","JPN":"すでに連鎖反応が始まってしまった以上、この事態を収束するためには\\nある程度のリスクを覚悟のうえで、圧倒的な力で\\n断ち切るしかないだろう。","ENG":"The chain reaction has already started. It's best to put it all to rest quickly with overwhelming strength, although it means we'll have to take some damage.","TWN":"在連鎖反應已經開始的情況下，想要控制事態，就得承受一定的損失，用壓倒性的力量結束這一切才是上策。"},"stage":{"bg":"MAINSTREAM_423010","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L20_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"그리고 내가 아니면......","JPN":"それに、私以外に……","ENG":"Besides, I'm the only one left here...","TWN":"還有，如果不是我……"},"stage":{"bg":"MAINSTREAM_423010","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L21_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"이곳엔 이미 5종 침식체급으로 성장해 버린 저 <color=#ffd34c>테라사이드의 가마솥</color>을 파괴할 자가 없으니까.","JPN":"すでに第5種侵食体級に成長してしまった\\n<color=#ffd34c>テラサイドの釜</color>を破壊できる者は、ここにはいない。","ENG":"who's capable of destroying the <color=#ffd34c>Cauldron of the Terraside</color>, which has become as threatening as a Category 5 C.O.","TWN":"這裡沒有人能夠破壞已經成長為第5級侵蝕體的<color=#ffd34c>特拉賽德之釜</color>。"},"stage":{"bg":"MAINSTREAM_423010","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L25_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"말은 그럴싸하군요.","JPN":"おっしゃることは、もっともらしいですね。","ENG":"You try to make it sound reasonable,","TWN":"聽起來非常有道理。"},"stage":{"bg":"MAINSTREAM_5505011","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L26_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"그 설계도의 근본인 미나 양을 처분하지 않는 것만 빼면 말이죠.","JPN":"その設計図の元であるミナさんを処分しないことを除いて。","ENG":"but you haven't done anything with Mina, the very root of the blueprint, have you?","TWN":"除了不處分那個設計圖的根源米娜小姐以外。"},"stage":{"bg":"MAINSTREAM_5505011","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L27_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"MAINSTREAM_5505011","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L28_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"구구절절한 이야기를 늘어놓고 계시지만 제가 보기에는 그저 미나 양을 구하러 가기 위한 변명으로밖에는 들리지 않는군요.","JPN":"さっきから長々と話していますが、私にはミナさんを\\n救いに行くための口実にしか聞こえませんね。","ENG":"Every single word you say sound like a mere excuse you're making up to go save Mina.","TWN":"您說了這麼多，在我看來也不過是為了去救米娜小姐的藉口而已。"},"stage":{"bg":"MAINSTREAM_5505011","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L29_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"애초에 나유빈을 요격하는 대신 여기로 온 것 자체가......","JPN":"そもそも、イチノセ・カオルを迎撃せずに\\nここに来ていること自体が……","ENG":"You coming here instead of launching an attack against Na Yubin was actually—","TWN":"說到底，您不迎擊羅瑜斌，反而來到這裡這件事本身……"},"stage":{"bg":"MAINSTREAM_5505011","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L30_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"함교!","JPN":"艦橋！","ENG":"Bridge!","TWN":"艦橋！"},"stage":{"bg":"MAINSTREAM_5505011","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L31_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"강하한다! 램프도어 개방!","JPN":"降下する！ ランプドア開放！","ENG":"I'm going down! Open the ramp door!","TWN":"我要降落了！打開艙門！"},"stage":{"bg":"MAINSTREAM_5505011","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L33_1","type":"dialog","speaker":"LENA_COFFIN_NULL_NULL","text":{"KOREA":"<color=#ffd34c>래, 램프도어 개방합니다!</color>","JPN":"<color=#ffd34c>ラ、ランプドア……開放します！</color>","ENG":"<color=#ffd34c>O-opening ramp door!</color>","TWN":"<color=#ffd34c>艙、艙門開啟！</color>"},"stage":{"bg":"MAINSTREAM_5505011","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L38_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"MAINSTREAM_5505012","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_COMBAT_MECHANIC_GAMECHANGER_HYPER_SKILL_START"},{"id":"L39_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"후우, 정말이지......","JPN":"ふう、まったく……","ENG":"*Sigh* She's so stubborn.","TWN":"呼，真是的……"},"stage":{"bg":"MAINSTREAM_5505012","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L40_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"어쨌거나 당신도 실망했겠군요.","JPN":"これであなたも失望したんじゃありませんか？","ENG":"I assume you're quite disappointed in yourself.","TWN":"不管怎麼樣，你肯定也很失望吧。"},"stage":{"bg":"MAINSTREAM_5505012","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_SIREN"},{"id":"L41_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"기껏 서윤 양을 시켜 안배해 놓은 계획들이 전부 무용지물이 되었으니......","JPN":"せっかくシズカさんに頼んでいた計画が、すべて無駄になってしまいましたから。","ENG":"All the plans you prepared with Seo Yoon got thrown out the window...","TWN":"費盡千辛萬苦，安排徐芸小姐所進行的計畫，現在全部作廢了……"},"stage":{"bg":"MAINSTREAM_5505012","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L42_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"천만에, 미나 양은 아주 잘 해내고 있네.","JPN":"とんでもない。ミナ君がとても良い仕事をしてくれているんだ。","ENG":"Oh no, Mina is doing great.","TWN":"沒這回事，米娜小姐做得很好呢。"},"stage":{"bg":"MAINSTREAM_5505012","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L43_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"오히려 그녀가 비숍을 살해했다면 난 아주 실망했을 거야.","JPN":"もし彼女がビショップを殺してたら、むしろその方が失望してただろうな。","ENG":"I'd have been very disappointed if she had killed Bishop.","TWN":"要是她殺了主教，我反而會非常失望呢。"},"stage":{"bg":"MAINSTREAM_5505012","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L44_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그래서야 지난번에 비해 발전이 전혀 없지.","JPN":"それだと、前回と比べて何も成長してないじゃないか。","ENG":"That would have meant that she hadn't made any progress since last time.","TWN":"這樣和上次相比完全沒有進步。"},"stage":{"bg":"MAINSTREAM_5505012","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L45_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"하지만 미나 양은 자신이 증오의 연쇄를 끊어낼 수 있다는 잠재력을 보여줬어. 아주 훌륭해.","JPN":"しかしミナ君は、憎しみの連鎖を自分で断ち切れるという可能性を見せてくれた。立派なものだ。","ENG":"But Mina showed me that she was strong enough to end the chain of hate. I'm very impressed.","TWN":"但是米娜小姐展現出了斬斷憎恨的可能性，非常好。"},"stage":{"bg":"MAINSTREAM_5505012","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L46_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"이렇게 기대 이상의 모습을 보여 줘야 나도 그녀를 기다렸던 보람이 있지 않겠나?","JPN":"こうやって期待以上の可能性を見せてくれなければ、\\nこれまで彼女の成長を待ったかいがないじゃないか。","ENG":"It's pleasant to know that she has gone beyond my expectations. It means I haven't waited for nothing.","TWN":"她若沒有這樣超乎期待的表現，我不就也沒有等待她的價值了嗎？"},"stage":{"bg":"MAINSTREAM_5505012","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L47_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"<color=#ffd34c>지난번</color>이라......","JPN":"<color=#ffd34c>前回</color>ですか……","ENG":"Since <color=#ffd34c>last time</color>, huh...","TWN":"<color=#ffd34c>上次</color>……"},"stage":{"bg":"MAINSTREAM_5505012","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L48_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"당신도 스승님과 똑같군요.","JPN":"あなたも師匠と同じなんですね。","ENG":"You're just like Master.","TWN":"您和師父一樣呢。"},"stage":{"bg":"MAINSTREAM_5505012","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L49_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"그래서 미나 양의 달라진 모습을 보기 위해 지금까지 유출을 막아 온 테크 레벨 5 블랙홀 드라이브도 공개한 건가요?","JPN":"ミナさんの変わった姿を見るために、\\nこれまで隠してきたテックレベル5のブラックホールドライブも公開したのですか？","ENG":"Was that why you unleashed the Tech Level 5 black hole drive to everyone, to see how much Mina has improved?","TWN":"所以您就為了看到米娜小姐改變的模樣，才公開了一直防止流出的等級5黑洞引擎技術嗎？"},"stage":{"bg":"MAINSTREAM_5505012","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L1_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"하하, 무슨 말인지 모르겠군.","JPN":"ハハ、何のことかわからないな。","ENG":"Hah hah, I don't know what you're talking about.","TWN":"哈哈，我不知道妳在說什麼。"},"stage":{"bg":"MAINSTREAM_5505012","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L2_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그건 관리국에서 공개한 기술이지 않나? 왜 내게......","JPN":"あれは管理局が公開した技術じゃないか。なぜ私に……","ENG":"It was the Administration that revealed it. Why are you asking me?","TWN":"那不是管理局公開的技術嗎？為什麼問我……"},"stage":{"bg":"MAINSTREAM_5505012","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"당신이 최고관리위원회의 0호 관리자라는 걸 제가 모를 것 같습니까?","JPN":"あなたが最高管理委員会の第0号管理者であることを、私が知らないとでも？","ENG":"Oh, please. I'm well aware that you're the highest-rank administrator in the High Committee.","TWN":"您就是管理局最高管理委員會的零號管理者，您以為我會不知道嗎？"},"stage":{"bg":"MAINSTREAM_5505012","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"우리 같은 작은 회사가 정식으로 태스크포스 인증을 받은 것도,","JPN":"我々みたいに小さな会社が正式にタスクフォースの認証を受けたのも、","ENG":"A small company like us getting an official TASKFORCE license,","TWN":"我們這樣的小公司能夠獲得正式的特遣勢力認證也是……"},"stage":{"bg":"MAINSTREAM_5505012","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"서윤 양이 정식 카운터 라이선스를 받은 것도,","JPN":"シズカさんがカウンターとしての正式ライセンスを取得したのも、","ENG":"as well as Seo Yoon becoming a licensed Counter,","TWN":"徐芸小姐能獲得制裁者正式執照也是……"},"stage":{"bg":"MAINSTREAM_5505012","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"모두 당신의 입김이 작용한 결과겠죠.","JPN":"すべてあなたが仕組んだ結果でしょうね。","ENG":"would have been impossible if it hadn't been for you.","TWN":"這一切都是在您影響之下的結果吧。"},"stage":{"bg":"MAINSTREAM_5505012","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"애초에 관리실패로 구 관리국이 망한 후 현실세계에 지금의 새로운 관리국을 만든 게 당신이니까요.","JPN":"そもそも管理失敗によって旧管理局が壊滅した後、\\n現実世界に現在の新管理局を立て直したのがあなたですから。","ENG":"After all, you were the one who created the new Administration in the Normalside after the Administration Failure took the old one down.","TWN":"畢竟，舊管理局因為管理失敗滅亡後，在現實世界建立新管理局的也是您啊。"},"stage":{"bg":"MAINSTREAM_5505012","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"......역시 우수한 인재로군.","JPN":"……やっぱり優秀な人材だな。","ENG":"You're a brilliant soul, just like I thought you'd be.","TWN":"……果然是個優秀的人才呢。"},"stage":{"bg":"MAINSTREAM_5505012","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"자네를 대리자로 선택한 건 정말 좋은 결정이었던 것 같아.","JPN":"君を代理人として選んだのは、実に素晴らしい決定だったようだ。","ENG":"It was the right decision to make you the proxy.","TWN":"選擇妳作為代理者果真是個正確的決定。"},"stage":{"bg":"MAINSTREAM_5505012","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"MAINSTREAM_5505012","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L13_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"너무 그렇게 걱정할 필요 없네.","JPN":"だが、そこまで案ずることはない。","ENG":"You can relax, there's nothing to be worried about.","TWN":"不用太過擔心。"},"stage":{"bg":"MAINSTREAM_5505012","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L14_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"어차피 이번 사태로 불멸체 코어가 유출된 이상 테크레벨 5의 원천 기술이 퍼져나가는 건 막을 수 없어.","JPN":"今回、不滅体コアが流出してしまった以上、\\nテックレベル5の独自技術が知れてしまうのは、もはや防げないことだ。","ENG":"The stories of Immortal System Core spread to the public through the recent series of events, and there was no way we could keep the Level 5 core technologies from leaking.","TWN":"反正這次的事件已經洩漏了不滅者核心，也沒有辦法阻止技術等級5的源頭科技擴散了。"},"stage":{"bg":"MAINSTREAM_5505012","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L15_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"블랙홀 드라이브가 좀 과하다고 생각할 수도 있겠지만......","JPN":"ブラックホールドライブに関しては、度が過ぎると思うかもしれないが……","ENG":"You may think I went too far by showing them the black hole drive,","TWN":"雖然黑洞引擎可能有點太超過……"},"stage":{"bg":"MAINSTREAM_5505012","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L16_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"어차피 그것만으로는 안정적으로 운용할 수 있는 기술이 아니니까 세계침식률 증가에는 큰 변동이 없을 거야.","JPN":"それだけで安定的に運用できる技術ではない。世界侵食率に大きな影響はないだろう。","ENG":"but by itself, the black hole drive is as unusable as a brick. There won't be any serious changes in the global Corruption rate.","TWN":"但反正那不是光靠那樣就可以穩定運用的技術，對世界侵蝕率的增加不會有太大的變動。"},"stage":{"bg":"MAINSTREAM_5505012","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L17_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"굳이 변명하자면 이런 사고를 친 <color=#ffd34c>리플레이서</color> 친구들에게도 벌은 필요할 테니까......","JPN":"言い訳をさせてもらうと、こんな事態を招いた\\n<color=#ffd34c>リプレイサー</color>どもにもお仕置きは必要だろうからな……","ENG":"If you need a more proper excuse, I'd have to say that the <color=#ffd34c>Replacer</color> fellows went a little too far,","TWN":"真要找個藉口的話，我們也得懲罰造成這次事件的<color=#ffd34c>克隆集團</color>朋友們才行……"},"stage":{"bg":"MAINSTREAM_5505012","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L18_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"조금 두꺼운 회초리를 꺼내든 거지. 딱 그 정도의 의미라고 보면 되네.","JPN":"太めのムチを取り出したわけだ。そういう意味で受け取ってほしい。","ENG":"and that was the punishment I thought they deserved. Nothing more, nothing less.","TWN":"拿出一條稍微粗一點的鞭子，差不多就是這個意思吧。"},"stage":{"bg":"MAINSTREAM_5505012","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L19_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"......일단은 그런 걸로 해 두죠.","JPN":"……ここはいったん、そういうことにしておきましょう。","ENG":"I'll try to believe you.","TWN":"……姑且就當作是這樣吧。"},"stage":{"bg":"MAINSTREAM_5505012","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L20_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"어차피 스승님이 칼을 빼든 이상, 그런 건 사소한 문제니까요.","JPN":"どのみち師匠が刀を抜いた以上、そんなことは些細な問題に過ぎませんから。","ENG":"Now that Master decided to act on it, anything else is a trivial matter anyway.","TWN":"反正師父都已經拔刀了，這都只是些小問題。"},"stage":{"bg":"MAINSTREAM_5505012","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L25_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"게임이...... 시작되겠군요.","JPN":"ゲームが……始まりますね。","ENG":"The game is about to begin...","TWN":"遊戲……就要開始了。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}}]`);export{e as default};